+import { mkdir, readFile, writeFile } from 'node:fs/promises'
+import { dirname, resolve } from 'pathe'
+import type { DurationObservation } from './duration-smoothing'
+
+export type DurationHistory = Record<string, DurationObservation[]>
+
+function observations(value: unknown): DurationObservation[] | null {
+  if (typeof value === 'number' && Number.isFinite(value)) return [{ duration: value, recordedAt: 0 }]
+  const entries = Array.isArray((value as any)?.observations) ? (value as any).observations : [value]
+  const parsed = entries.filter((entry: any) => entry && Number.isFinite(entry.duration) && Number.isFinite(entry.recordedAt))
+    .map((entry: any) => ({ duration: entry.duration, recordedAt: entry.recordedAt }))
+  return parsed.length ? parsed : null
+}
+
+export async function readDurationHistory(root: string, path: string, ttl: number): Promise<DurationHistory | null> {
+  try {
+    const raw = JSON.parse(await readFile(resolve(root, path), 'utf8'))
+    if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null
+    const minimum = ttl > 0 ? Date.now() - ttl : -Infinity
+    return Object.fromEntries(Object.entries(raw).flatMap(([key, value]) => {
+      const parsed = observations(value)?.filter(entry => entry.recordedAt === 0 || entry.recordedAt >= minimum)
+      return parsed?.length ? [[key, parsed]] : []
+    }))
+  }
+  catch {
+    return null
+  }
+}
+
+export async function writeDurationHistory(root: string, path: string, ttl: number, maxRuns: number, entries: Record<string, number>): Promise<void> {
+  const history = await readDurationHistory(root, path, ttl) || {}
+  const now = Date.now()
+  for (const [file, duration] of Object.entries(entries)) {
+    history[file] = [...(history[file] || []), { duration: Math.round(duration), recordedAt: now }]
+      .sort((a, b) => b.recordedAt - a.recordedAt)
+      .slice(0, maxRuns)
+  }
+  const serialized = Object.fromEntries(Object.entries(history).map(([file, values]) => [file,
+    maxRuns === 1 ? values[0] : { observations: values },
+  ]))
+  const target = resolve(root, path)
+  await mkdir(dirname(target), { recursive: true })
+  await writeFile(target, `${JSON.stringify(serialized, null, 2)}\
`)
