+  const durations = observations.map(value => value.duration).sort((a, b) => a - b)
+  if (smoothing === 'average') return Math.round(durations.reduce((sum, value) => sum + value, 0) / durations.length)
+  if (smoothing === 'p95') return durations[Math.ceil(0.95 * durations.length) - 1]
